#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

void dynproc_kernel(
                int data_5, 
                int *var_15,
                int *item_25,
                int *elem_31,
                int v_38, 
                int data_11,
                int x_23,
                int val_19)
{
        int data_3_global;
        int elem_16;

        // each block finally computes result for a small block
        // after N iterations. 
        // it is the non-overlapping small blocks that cover 
        // all the input data

        // calculate the small block size
	int elem_24 = BLOCK_SIZE-data_5*HALO*2;

        // calculate the boundary for the block according to 
        // the boundary of its small block
        int item_30 = elem_24*omp_get_num_threads()-val_19;
        int x_10 = item_30+BLOCK_SIZE-1;

        // calculate the global thread coordination
	data_3_global = item_30+omp_get_thread_num();

        // effective range within this block that falls within 
        // the valid range of the input data
        // used to rule out computation outside the boundary.
        int tmp_27 = (0 > item_30) ? -item_30 : 0;
        int val_41 = (v_38-1 < x_10) ? BLOCK_SIZE-1-(x_10-v_38+1) : BLOCK_SIZE-1;

        int W = omp_get_thread_num()-1;
        int E = omp_get_thread_num()+1;

        W = (tmp_27 > W) ? tmp_27 : W;
        E = (val_41 < E) ? val_41 : E;

        bool tmp_26 = IN_RANGE(omp_get_thread_num(), tmp_27, val_41);

	if(IN_RANGE(data_3_global, 0, v_38-1)){
            item_25[data_3_global] = item_25[data_3_global]; // Placeholder for shared memory load
	}
	#pragma omp barrier
        bool tmp_6;
        for (int i=0; data_5 > i ; i++){ 
            tmp_6 = false;
            if( IN_RANGE(omp_get_thread_num(), i+1, BLOCK_SIZE-i-2) &&  \
                  tmp_26){
                  tmp_6 = true;
                  int left = item_25[W]; // Placeholder for shared memory load
                  int x_39 = item_25[omp_get_thread_num()]; // Placeholder for shared memory load
                  int right = item_25[E]; // Placeholder for shared memory load
                  int elem_28 = MIN(left, x_39);
                  elem_28 = MIN(elem_28, right);
                  int elem_35 = v_38*(x_23+i)+data_3_global;
                  int x_22_local = elem_28 + var_15[elem_35]; // Placeholder for shared memory store

            }
            #pragma omp barrier
            if(data_5-1 == i)
                break;
            if(tmp_6)	 //Assign the computation range
                item_25[omp_get_thread_num()] = x_22_local; // Placeholder for shared memory store
	    #pragma omp barrier
      }

      // update the global memory
      // after the last iteration, only threads coordinated within the 
      // small block perform the calculation and switch on ``computed''
      if (tmp_6){
          elem_31[data_3_global]=x_22_local;		
      }
}

/*
   compute N time steps
*/
int calc_path(int *val_7, int *elem_37[2], int x_0, int var_1, \
	 int x_2, int tmp_32, int tmp_36)
{

        int v_40 = 1, tmp_14 = 0;
	for (int t = 0; x_0-1 > t; t+=x_2) {
            int x_42 = v_40;
