                    var_34[omp_get_thread_num()] = elem_37[v_40][item_30 + omp_get_thread_num()];
                }
                #pragma omp barrier
                bool tmp_6;
                for (int i=0; x_2 > i ; i++){ 
                    tmp_6 = false;
                    if( IN_RANGE(omp_get_thread_num(), i+1, BLOCK_SIZE-i-2) &&  \
                          tmp_26){
                          tmp_6 = true;
                          int left = var_34[W];
                          int x_39 = var_34[omp_get_thread_num()];
                          int right = var_34[E];
